async function handleSubmit(data: AddLocationData) {
  try {
    setIsSubmitting(true);

    const supabase = createClient();
    const { data: { session } } = await supabase.auth.getSession();

    const response = await fetch(`/api/projects/${projectId}/candidates`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${session.access_token}`
      },
      body: JSON.stringify({
        location_name: data.location_name,
        address: data.address,
        category: data.category,
        lat: data.lat,
        lng: data.lng
      })
    });

    if (!response.ok) {
      throw new Error('후보지 등록 실패');
    }

    const result = await response.json();
    toast.success('후보지가 등록되었습니다');
    onClose();

    // 부모 컴포넌트에 알림 (candidates 상태 업데이트용)
    if (onSuccess) {
      onSuccess(result);
    }
  } catch (error) {
    toast.error('후보지 등록 실패');
  } finally {
    setIsSubmitting(false);
  }
}

