interface CandidateCardProps {
  candidate: CandidateWithUserVote;
  index: number;
  onVote: (candidateId: string, voteType: 'agree' | 'disagree') => Promise<void>;
  onDelete: (candidateId: string) => Promise<void>;
  className?: string;
}

function CandidateCard({ candidate, index, onVote, onDelete }: CandidateCardProps) {
  const [isVoting, setIsVoting] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);

  const total = candidate.votes_agree + candidate.votes_disagree;
  const ratio = candidate.agreement_ratio || 0;

  // 결과 아이콘 결정
  let resultIcon = '-';
  let resultColor = 'text-gray-400';
  if (total > 0) {
    if (ratio >= 66) {
      resultIcon = '✓';
      resultColor = 'text-green-600';
    } else {
      resultIcon = '✕';
      resultColor = 'text-gray-700';
    }
  }

  // 투표 핸들러 (낙관적 업데이트)
  async function handleVote(voteType: 'agree' | 'disagree') {
    if (isVoting) return;

    // 같은 버튼 재클릭 시 투표 취소
    const finalVoteType = candidate.user_vote === voteType ? null : voteType;

    setIsVoting(true);
    await onVote(candidate.id, finalVoteType);
    setIsVoting(false);
  }

  return (
    <div className="flex flex-col gap-3 p-4 bg-white rounded-lg border border-gray-200">
      {/* 헤더: 번호, 장소명, 주소, 카테고리 */}
      <div className="flex items-start gap-3">
        <span className="bg-blue-600 text-white rounded-full w-8 h-8 flex items-center justify-center text-sm font-bold">{index + 1}</span>
        <div className="flex-1">
          <h4 className="font-semibold text-gray-900">{candidate.location_name}</h4>
          <p className="text-sm text-gray-600">{candidate.address}</p>
          {candidate.category && <span className="text-xs text-gray-500">{candidate.category}</span>}
        </div>
        <Button variant="ghost" size="sm" onClick={() => onDelete(candidate.id)} disabled={isDeleting}>삭제</Button>
      </div>

      {/* 투표 UI */}
      <div className="flex items-center justify-between gap-4">
        <div className="flex gap-2">
          <Button variant={candidate.user_vote === 'agree' ? 'default' : 'outline'} size="sm" onClick={() => handleVote('agree')} disabled={isVoting}>👍 {candidate.votes_agree}명</Button>
          <Button variant={candidate.user_vote === 'disagree' ? 'default' : 'outline'} size="sm" onClick={() => handleVote('disagree')} disabled={isVoting}>👎 {candidate.votes_disagree}명</Button>
        </div>
        <span className={`text-3xl font-bold ${resultColor}`}>{resultIcon}</span>
      </div>
    </div>
  );
}

