interface CandidateListProps {
  projectId: string;
  className?: string;
}

function CandidateList({ projectId }: CandidateListProps) {
  const [candidates, setCandidates] = useState<CandidateWithUserVote[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // 초기 로드
  useEffect(() => {
    fetchCandidates();
  }, [projectId]);

  async function fetchCandidates() {
    try {
      setLoading(true);
      const supabase = createClient();
      const { data: { session } } = await supabase.auth.getSession();

      const response = await fetch(`/api/projects/${projectId}/candidates`, {
        headers: { Authorization: `Bearer ${session.access_token}` }
      });

      const data = await response.json();
      setCandidates(data);
    } catch (err) {
      setError('후보지 조회 실패');
    } finally {
      setLoading(false);
    }
  }

  // 투표 핸들러 (낙관적 업데이트)
  async function handleVote(candidateId: string, voteType: 'agree' | 'disagree' | null) {
    // 1단계: 낙관적 UI 업데이트
    setCandidates(prev => prev.map(c => {
      if (c.id !== candidateId) return c;

      let newAgree = c.votes_agree;
      let newDisagree = c.votes_disagree;
      const oldVote = c.user_vote;

      if (oldVote === 'agree') newAgree--;
      else if (oldVote === 'disagree') newDisagree--;

      if (voteType === 'agree') newAgree++;
      else if (voteType === 'disagree') newDisagree++;

      const total = newAgree + newDisagree;
      const ratio = total === 0 ? 0 : (newAgree / total) * 100;

      return {
        ...c,
        votes_agree: newAgree,
        votes_disagree: newDisagree,
        user_vote: voteType,
        agreement_ratio: Math.round(ratio * 10) / 10
      };
    }));

    // 2단계: API 호출
    try {
      const supabase = createClient();
      const { data: { session } } = await supabase.auth.getSession();

      const response = await fetch(`/api/projects/${projectId}/candidates/${candidateId}/vote`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${session.access_token}` },
        body: JSON.stringify({ vote_type: voteType })
      });

      const result = await response.json();

      // 3단계: 서버 응답으로 실제 값 업데이트
      setCandidates(prev => prev.map(c => c.id === candidateId ? { ...c, ...result.candidate } : c));
    } catch (error) {
      toast.error('투표 실패');
      fetchCandidates(); // 롤백
    }
  }

  // 삭제 핸들러
  async function handleDelete(candidateId: string) {
    if (!confirm('이 후보지를 삭제하시겠습니까?')) return;

    try {
      const supabase = createClient();
      const { data: { session } } = await supabase.auth.getSession();

      const response = await fetch(`/api/projects/${projectId}/candidates/${candidateId}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${session.access_token}` }
      });

      if (!response.ok) throw new Error('삭제 실패');

      toast.success('후보지가 삭제되었습니다');
      setCandidates(prev => prev.filter(c => c.id !== candidateId));
    } catch (error) {
      toast.error('삭제 실패');
    }
  }

  if (loading) return <div>로딩 중...</div>;
  if (error) return <div>{error}</div>;
  if (candidates.length === 0) return <div>후보지가 없습니다.</div>;

  return (
    <div className="space-y-3">
      {candidates.map((candidate, index) => (
        <CandidateCard
          key={candidate.id}
          candidate={candidate}
          index={index}
          onVote={handleVote}
          onDelete={handleDelete}
        />
      ))}
    </div>
  );
}

