interface NaverMapProps {
  searchResults: LocationSearchResult[];
  selectedLocation: LocationSearchResult | null;
  onLocationSelect: (location: LocationSearchResult | null) => void;
  onAddLocation?: () => void;
  userRole?: 'creator' | 'member';
  candidates?: CandidateWithUserVote[]; // 새로 추가
  className?: string;
}

// 마커 색상 계산 함수
function getMarkerColor(candidate: CandidateWithUserVote): string {
  const total = candidate.votes_agree + candidate.votes_disagree;
  if (total === 0) return '#9CA3AF'; // 회색 (투표 없음)

  const ratio = (candidate.votes_agree / total) * 100;
  if (ratio >= 66) return '#10B981'; // 초록 (찬성 >= 66%)
  return '#EF4444'; // 빨강 (찬성 < 66%)
}

// useEffect 추가: candidates 변경 시 후보지 마커 렌더링
useEffect(() => {
  if (!mapRef.current || !window.naver || !candidates) return;

  // 기존 후보지 마커 제거 (candidateMarkersRef 추가 필요)
  candidateMarkersRef.current.forEach(marker => marker.setMap(null));
  candidateMarkersRef.current = [];

  // 새 후보지 마커 생성
  candidates.forEach(candidate => {
    const position = new window.naver.maps.LatLng(candidate.lat, candidate.lng);
    const markerColor = getMarkerColor(candidate);

    const marker = new window.naver.maps.Marker({
      position,
      map: mapRef.current,
      title: candidate.location_name,
      icon: {
        content: `<div class="flex items-center justify-center w-6 h-6 rounded-full text-white text-xs font-bold border-2 border-white shadow-lg" style="background-color: ${markerColor};"></div>`,
        anchor: new window.naver.maps.Point(12, 12)
      }
    });

    candidateMarkersRef.current.push(marker);
  });
}, [candidates]);

